pragma solidity ^0.8.0;

contract OptimizedCode {
    uint[] public data;

    function unOptimizedProcess(uint[] memory values) public {
        for(uint i = 0; i < values.length; i++) {
            if(values[i] > 10) {
                data.push(values[i]);
            }
         }
    }

    function optimizedProcess(uint[] calldata values) external {
        uint len = values.length;
        // дҪҝз”Ёдёҙж—¶ memoryж•°з»„еҸҳйҮҸжүӢжңәз¬ҰеҗҲжқЎд»¶зҡ„еҖј
        uint[] memory temps = new uint[](len);
        uint count = 0;
        for (uint i = 0; i < len; i++) 
        {
            uint val = values[i];
            if (val > 10) {
               temps[count] = val;
               count++;
            }
        }

        // жү№йҮҸpush,иҝһз»ӯж“ҚдҪңжӣҙзңҒgas
        for (uint i = 0; i < temps.length; i++) 
        {
            data.push(temps[i]);
        }
    }

    // жңҖдјҳи§Ј
    function process(uint[] calldata values) external {
        uint len = values.length;
        uint currentLen = data.length;
        uint count = 0;
        // з¬¬дёҖж¬ЎйҒҚеҺҶпјҡи®Ўз®—з¬ҰеҗҲжқЎд»¶зҡ„ж•°йҮҸ
        for (uint i = 0; i < len; i++) 
        {
            if (values[i] > 10) {
                count++;
            }
        }

        // йў„е…Ҳжү©еұ•ж•°з»„,дёҖж¬ЎжҖ§еҶҷе…Ҙй•ҝеәҰ
        if (count > 0) {
            uint newLen = currentLen + count;
            assembly{
                // зӣҙжҺҘжү©еұ•ж•°з»„в»“еәҰпјҢйҒҝе…ҚеӨҡж¬Ў push
                sstore(add(data.slot, 0), newLen)
            }
        }

        // з¬¬дәҢж¬ЎйҒҚеҺҶ:зӣҙжҺҘиөӢеҖјеҲ°е·Із»ҸеҲҶй…Қзҡ„дҪҚзҪ®
        uint index = currentLen;
        for (uint i = 0; i < len; i++) 
        {
            if (values[i] > 10) {
                // зӣҙжҺҘиөӢеҖјжҜ”pushжӣҙзңҒgas
                data[index] = values[i];
                index++;
            }
        }
    }
}

