// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
д»»еҠЎиҰҒжұӮпјҡ
еҲӣе»әвјҖдёӘе®Ңж•ҙзҡ„ж•°з»„з®ЎзҗҶеҗҲзәҰпјҢе®һзҺ°д»ҘдёӢеҠҹиғҪпјҡ
1. йҷҗеҲ¶жңҖвјӨв»“еәҰдёә100
2. е®һзҺ°е®үе…Ёзҡ„ж·»еҠ еҠҹиғҪпјҲsafePushпјү
3. е®һзҺ°дёӨз§ҚеҲ йҷӨвҪ…жі•пјҲдҝқеәҸе’Ңеҝ«йҖҹпјү
4. е®һзҺ°еҲҶжү№жұӮе’ҢеҠҹиғҪпјҲsumRangeпјү
5. е®һзҺ°жҹҘжүҫеҠҹиғҪпјҲиҝ”еӣһе…ғзҙ зҙўеј•пјү
6. е®һзҺ°иҺ·еҸ–жүҖжңүе…ғзҙ еҠҹиғҪ
*/
contract SafeArrayManager {
    uint[] public data;
    uint public constant MAX_SIZE = 100;

    event ElementAdded(uint value,uint index);
    event ElementRemoved(uint index,uint value);

    // е®үе…Ёж·»еҠ 
    function safePush(uint value) public {
        // жЈҖжҹҘеӨ§е°ҸйҷҗеҲ¶
        require(data.length < MAX_SIZE, "Data is full!");
        // ж·»еҠ е…ғзҙ 
        data.push(value);
        emit ElementAdded(value, data.length - 1);
    }

    // дҝқеәҸеҲ йҷӨ
    function removeOrdered(uint index) public {
        // жЈҖжҹҘзҙўеј•
        require(index < data.length,"Index out of bouds!");
        uint removeValue = data[index];
        // з§»еҠЁе…ғзҙ 
        for (uint i = index; i < data.length - 1; i++) 
        {
            data[i] = data[i + 1];
        }
        // popжңҖеҗҺе…ғзҙ 
        data.pop();
        emit ElementRemoved(index, removeValue);
    }

    // еҝ«йҖҹеҲ йҷӨ
    function removeUnordered(uint index) public {
        // жЈҖжҹҘзҙўеј•
        require(index < data.length, "Index out of bounds!");
        uint removeValue = data[index];
        // жӣҝжҚўдёәжңҖеҗҺе…ғзҙ 
        data[index] = data[data.length - 1];
        // pop
        data.pop();
        emit ElementRemoved(index, removeValue);
    }

    // еҲҶжү№жұӮе’Ң
    function sumRange(uint start,uint end) public view returns (uint) {
        // жЈҖжҹҘиҢғеӣҙ
        require(start < end,"Start < end !");
        require(end <= data.length, "Index out of bounds!");
        // и®Ўз®—жҖ»е’Ң
        uint total = 0;
        for (uint i = start; i < end; i++) 
        {
            total += data[i];
        }
        return total;
    }

    // жҹҘжүҫе…ғзҙ 
    function findElement(uint value) public view returns (bool,uint) {
        // йҒҚеҺҶжҹҘжүҫ
        uint len = data.length;
        for (uint i = 0; i < len; i++) 
        {
            if (data[i] == value) {
                return (true,i);
            }
        }
        // иҝ”еӣһжҳҜеҗҰжүҫеҲ°е’Ңзҙўеј•
        return (false,0); 
    }

    // иҺ·еҸ–жүҖжңүе…ғзҙ 
    function getAll() public view returns (uint[] memory) {
        // иҝ”еӣһж•ҙдёӘж•°з»„
        return data;
    }
}

